// ── 국회의원 조회 함수 ──

export function getLegislators(): Legislator[] {
  return LEGISLATORS_DATA;
}

export function getLegislatorById(id: string): Legislator | undefined {
  return LEGISLATORS_DATA.find(l => l.id === id);
}

export function getLegislatorsByParty(party: string): Legislator[] {
  return LEGISLATORS_DATA.filter(l => l.party === party);
}
